// src/components/member/MemberAchievements.jsx
import { useState, useEffect } from "react";
import { useAuth } from "../../hooks/useAuth";
import { fmtDT } from "../../lib/constants";
import { collection, onSnapshot, query, where, orderBy, addDoc, serverTimestamp } from "firebase/firestore";
import { db } from "../../lib/firebase";
import { Card, Btn, TA, ST, Spinner, Empty, Modal, useToast } from "../shared/UI";

export default function MemberAchievements() {
  const { profile } = useAuth();
  const { toast, ToastContainer } = useToast();
  const [tasks, setTasks]           = useState([]);
  const [myApps, setMyApps]         = useState([]);
  const [loading, setLoading]       = useState(true);
  const [applyModal, setApplyModal] = useState(null);

  useEffect(() => {
    const q1 = query(collection(db,"achievements"), where("status","==","active"), orderBy("createdAt","desc"));
    const unsub1 = onSnapshot(q1, snap => {
      setTasks(snap.docs.map(d=>({id:d.id,...d.data()})));
    });
    const q2 = query(collection(db,"achievementApplications"), where("memberId","==",profile.id), orderBy("submittedAt","desc"));
    const unsub2 = onSnapshot(q2, snap => {
      setMyApps(snap.docs.map(d=>({id:d.id,...d.data()})));
      setLoading(false);
    });
    return () => { unsub1(); unsub2(); };
  }, [profile.id]);

  function getMyApp(taskId, color) {
    return myApps.find(a => a.taskId === taskId && a.targetColor === color);
  }

  if (loading) return <Spinner />;

  return (
    <div className="p-4 flex flex-col gap-4">
      <ToastContainer />

      <div className="bg-amber-500/10 border border-amber-400/30 rounded-xl p-3">
        <div className="text-amber-300 text-xs font-bold mb-1">рҹ“Ӣ д»»еӢҷиӘӘжҳҺ</div>
        <div className="text-amber-200/80 text-xs leading-relaxed">
          е®ҢжҲҗд»»еӢҷжўқд»¶еҫҢпјҢй»һгҖҢз”іи«Ӣй ҳз« гҖҚйҖҒеҮәз”іи«ӢпјҢзӯүж•ҷз·ҙеҜ©ж ёйҖҡйҒҺеҫҢзі»зөұжңғиҮӘеӢ•зҷјж”ҫжҲҗе°ұз« гҖӮиӢҘжңӘйҖҡйҒҺпјҢеҸҜдҝ®жӯЈеҫҢйҮҚж–°з”іи«ӢгҖӮ
        </div>
      </div>

      {tasks.length === 0 && <Empty icon="рҹҸҶ" message="зӣ®еүҚжІ’жңүйҖІиЎҢдёӯзҡ„д»»еӢҷ" />}

      {tasks.map(task => (
        <Card key={task.id} className="p-4">
          <div className="flex items-start justify-between mb-3">
            <div>
              <div className="text-gray-100 font-bold text-sm">{task.title}</div>
              {task.expiresAt && <div className="text-red-400 text-xs mt-0.5">жҲӘжӯўж—Ҙжңҹпјҡ{task.expiresAt}</div>}
            </div>
            {task.expiresAt && new Date(task.expiresAt) < new Date()
              ? <span className="text-xs bg-red-500/15 text-red-400 font-bold px-2 py-0.5 rounded-full">е·ІжҲӘжӯў</span>
              : <span className="text-xs bg-green-500/15 text-green-300 font-bold px-2 py-0.5 rounded-full">йҖІиЎҢдёӯ</span>
            }
          </div>

          <div className="flex flex-col gap-2">
            {[["silver","рҹҘҲ йҠҖз« ","silverTask"],["gold","рҹҘҮ йҮ‘з« ","goldTask"],["black","в¬ӣ й»‘з« ","blackTask"]].map(([color,label,key])=>{
              if (!task[key]) return null;
              const myApp = getMyApp(task.id, color);
              const bgMap = { silver:"bg-white/5 border-white/15", gold:"bg-yellow-500/10 border-yellow-400/30", black:"bg-black/40 border-white/20" };
              const textMap = { silver:"text-gray-200", gold:"text-gray-200", black:"text-gray-200" };
              const subTextMap = { silver:"text-gray-400", gold:"text-gray-400", black:"text-gray-400" };
              const rejected = myApp?.status === "rejected";
              return (
                <div key={color} className={`rounded-xl p-3 border ${bgMap[color]}`}>
                  <div className={`font-bold text-xs mb-1 ${textMap[color]}`}>{label}</div>
                  <div className={`text-sm mb-1 ${textMap[color]}`}>{task[key]}</div>
                  {(task[`${key}Arrows`]||task[`${key}Distance`]||task[`${key}Target`]) && (
                    <div className={`text-xs mb-2 ${subTextMap[color]}`}>
                      {task[`${key}Arrows`]&&`${task[`${key}Arrows`]}ж”Ҝз®ӯ`}
                      {task[`${key}Distance`]&&`гҖҖ${task[`${key}Distance`]}зұі`}
                      {task[`${key}Target`]&&`гҖҖ${task[`${key}Target`]}`}
                    </div>
                  )}

                  {!myApp && (
                    <Btn v="secondary" size="sm" onClick={() => setApplyModal({ task, color, label })}>
                      з”іи«Ӣй ҳз« 
                    </Btn>
                  )}
                  {myApp?.status === "pending" && (
                    <div className="text-xs font-bold px-2 py-1 rounded-lg inline-block bg-yellow-500/15 text-yellow-300">
                      вҸі з”іи«ӢеҜ©ж ёдёӯ
                    </div>
                  )}
                  {myApp?.status === "approved" && (
                    <div className="text-xs font-bold px-2 py-1 rounded-lg inline-block bg-green-500/15 text-green-300">
                      вң… е·ІйҖҡйҒҺ
                    </div>
                  )}
                  {rejected && (
                    <div className="flex items-center gap-2 flex-wrap">
                      <span className="text-xs font-bold px-2 py-1 rounded-lg inline-block bg-red-500/15 text-red-400">
                        вқҢ жңӘйҖҡйҒҺ
                      </span>
                      <Btn v="secondary" size="sm" onClick={() => setApplyModal({ task, color, label })}>
                        рҹ”„ йҮҚж–°з”іи«Ӣ
                      </Btn>
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        </Card>
      ))}

      {myApps.length > 0 && (
        <div>
          <ST>жҲ‘зҡ„з”іи«ӢзҙҖйҢ„</ST>
          {myApps.map(a => {
            const task = tasks.find(t => t.id === a.taskId);
            return (
              <div key={a.id} className={`rounded-xl p-3 border mb-2
                ${a.status==="pending"?"bg-yellow-500/10 border-yellow-400/30":
                  a.status==="approved"?"bg-green-500/10 border-green-400/30":
                  "bg-white/5 border-white/15"}`}>
                <div className="flex items-center justify-between">
                  <div>
                    <div className="text-gray-200 text-sm font-medium">{task?.title || a.taskTitle || "д»»еӢҷ"}</div>
                    <div className="text-gray-400 text-xs">
                      {a.targetColor==="silver"?"рҹҘҲ йҠҖз« ":a.targetColor==="gold"?"рҹҘҮ йҮ‘з« ":"в¬ӣ й»‘з« "}
                      гҖҖ{fmtDT(a.submittedAt)}
                    </div>
                  </div>
                  <span className={`text-xs font-bold px-2 py-0.5 rounded-full
                    ${a.status==="pending"?"bg-yellow-500/15 text-yellow-300":
                      a.status==="approved"?"bg-green-500/15 text-green-300":
                      "bg-white/10 text-gray-400"}`}>
                    {a.status==="pending"?"еҜ©ж ёдёӯ":a.status==="approved"?"е·ІйҖҡйҒҺ":"жңӘйҖҡйҒҺ"}
                  </span>
                </div>
              </div>
            );
          })}
        </div>
      )}

      {applyModal && (
        <ApplyModal
          task={applyModal.task}
          color={applyModal.color}
          label={applyModal.label}
          profile={profile}
          onClose={() => setApplyModal(null)}
          onDone={() => { toast("з”іи«Ӣе·ІйҖҒеҮәпјҢзӯүеҫ…ж•ҷз·ҙеҜ©ж ё вң“"); setApplyModal(null); }}
        />
      )}
    </div>
  );
}

function ApplyModal({ task, color, label, profile, onClose, onDone }) {
  const [note, setNote]     = useState("");
  const [saving, setSaving] = useState(false);

  async function submit() {
    setSaving(true);
    await addDoc(collection(db, "achievementApplications"), {
      taskId: task.id,
      taskTitle: task.title,
      memberId: profile.id,
      memberName: profile.name,
      memberNickname: profile.nickname || "",
      targetColor: color,
      note,
      status: "pending",
      submittedAt: serverTimestamp(),
    });
    onDone();
    setSaving(false);
  }

  return (
    <Modal open onClose={onClose} title={`з”іи«Ӣ ${label} вҖ” ${task.title}`}>
      <div className="flex flex-col gap-4">
        <div className="bg-white/5 rounded-xl p-3 text-gray-300 text-sm">
          {task[`${color}Task`]}
          {task[`${color}TaskArrows`] && (
            <div className="text-gray-400 text-xs mt-1">
              {task[`${color}TaskArrows`]}ж”Ҝз®ӯгҖҖ{task[`${color}TaskDistance`]}зұігҖҖ{task[`${color}TaskTarget`]}
            </div>
          )}
        </div>
        <TA label="иЈңе……иӘӘжҳҺпјҲйҒёеЎ«пјү" value={note} rows={3}
          placeholder="иӘӘжҳҺдҪ жҳҜеҰӮдҪ•е®ҢжҲҗйҖҷеҖӢд»»еӢҷзҡ„вҖҰ"
          onChange={e => setNote(e.target.value)} />
        <div className="flex gap-2">
          <Btn v="secondary" className="flex-1" onClick={onClose}>еҸ–ж¶Ҳ</Btn>
          <Btn v="primary" className="flex-1" onClick={submit} disabled={saving}>
            {saving ? "йҖҒеҮәдёӯвҖҰ" : "йҖҒеҮәз”іи«Ӣ"}
          </Btn>
        </div>
      </div>
    </Modal>
  );
}